#!/usr/bin/env python3
"""
scripts/migrate_v4_schema.py
Purpose: One-time migration to add v4 model columns (height_cm, weight_kg,
         ftr) to an existing sessions.db created before the v4 upgrade.
         Safe to run multiple times (checks column existence first).
"""
import sys
from pathlib import Path
sys.path.insert(0, str(Path(__file__).parent.parent))
from config.config import Config
from database.db import get_connection

NEW_COLUMNS = {
    "height_cm": "REAL DEFAULT 175.0",
    "weight_kg": "REAL DEFAULT 75.0",
    "ftr": "REAL DEFAULT 1.20",
}

def migrate():
    conn = get_connection()
    existing = {row[1] for row in conn.execute("PRAGMA table_info(sessions)")}
    for col, ddl in NEW_COLUMNS.items():
        if col not in existing:
            print(f"Adding column: {col}")
            conn.execute(f"ALTER TABLE sessions ADD COLUMN {col} {ddl}")
        else:
            print(f"Column already exists, skipping: {col}")
    conn.commit()
    print("Migration complete.")

if __name__ == "__main__":
    migrate()
